import numpy as np
from scipy.spatial import ConvexHull

def validate_points(points):
    if not points:
        raise ValueError("Input list of points is empty")

    for point in points:
        if len(point) != 4:
            raise ValueError(f"Point {point} is not 4-dimensional")

    if len(points) < 1:
        raise ValueError("At least one point is required")

def four_dimensional_convex_hull(points):
    """
    Compute the convex hull of a set of 4D points.

    Args:
        points: A list of 4D points (each point is a list or tuple of 4 numbers).

    Returns:
        A tuple containing:
        - vertices: A list of indices of the input points that form the convex hull.
        - simplices: A list of simplices (tetrahedrons in 4D) that form the convex hull.
                    Each simplex is a tuple of indices of the vertices.
    """
    validate_points(points)

    if len(points) == 1:
        # Single point case - the hull is just the point itself
        return ([0], [])

    points_array = np.array(points)

    try:
        hull = ConvexHull(points_array)
    except Exception as e:
        if "QH6154" in str(e):
            # This typically means all points are coplanar or collinear in 4D
            # We'll try to handle lower-dimensional cases
            if len(points) < 5:
                # For 4 or fewer points, the hull is all points
                return (list(range(len(points))), [])

            # Try projecting to 3D and computing hull
            try:
                # Remove one dimension and try again
                projected_points = points_array[:, :3]
                hull_3d = ConvexHull(projected_points)
                return (hull_3d.vertices.tolist(), [])
            except:
                # If still fails, try 2D
                try:
                    projected_points = points_array[:, :2]
                    hull_2d = ConvexHull(projected_points)
                    return (hull_2d.vertices.tolist(), [])
                except:
                    # If all else fails, return all points
                    return (list(range(len(points))), [])
        else:
            raise e

    # Convert numpy arrays to Python lists/tuples for the output
    vertices = hull.vertices.tolist()
    simplices = [tuple(simplex) for simplex in hull.simplices]

    return (vertices, simplices)

