    """Compute the convex hull for 4D points."""
    points_array = validate_points(points)

    if len(points_array) == 0:
        return []
    elif len(points_array) == 1:
        return [points[0]]  # Return as list for consistency

    try:
        hull = ConvexHull(points_array)
        return [points[i] for i in hull.vertices]
    except:
        # Handle lower-dimensional cases (e.g., points on a 3D hyperplane)
        # We'll progressively reduce dimensions until we can compute a hull
        points_remaining = points_array.copy()
        for dim in reversed(range(1, 4)):
            try:
                if len(points_remaining) <= dim + 1:
                    continue
                hull = ConvexHull(points_remaining[:, :dim+1])
                basis = np.linalg.matrix_rank(points_remaining[:, :dim+1], tol=1e-10)
                if basis == len(points_remaining):
                    break
                points_remaining = points_remaining[hull.vertices]
            except:
                continue

        # Use the remaining points (they form the lower-dimensional convex hull)
        try:
            hull = ConvexHull(points_remaining)
            indices = hull.vertices
        except:
            indices = range(len(points_remaining))

        # Find original indices (since points_remaining may be a subset)
        original_indices = []
        remaining_points_set = {tuple(point) for point in points_remaining[indices]}
        for i, point in enumerate(points):
            if tuple(point) in remaining_points_set:
                original_indices.append(i)

        return [points[i] for i in original_indices]

