from scipy.spatial import ConvexHull

class ConvexHull4D:
    def __init__(self, points):
        self.points = np.array(points, dtype=float)
        self.validate_points()
        self.hull = None

    def validate_points(self):
        if len(self.points.shape) != 2 or self.points.shape[1] != 4:
            raise ValueError("Each point must have exactly 4 coordinates")
        if len(self.points) < 1:
            raise ValueError("At least one point is required")

    def compute(self):
        if len(self.points) == 1:
            return {
                'vertices': [0],
                'simplices': [],
                'neighbors': [],
                'point_indices': [0]
            }

        try:
            hull = ConvexHull(self.points)
            return {
                'vertices': hull.vertices.tolist(),
                'simplices': hull.simplices.tolist(),
                'neighbors': hull.neighbors.tolist(),
                'point_indices': hull.points.tolist()
            }
        except Exception as e:
            if "QH6214" in str(e):  # Qhull error for degenerate cases
                return self.handle_degenerate_case()
            raise

    def handle_degenerate_case(self):
        if len(self.points) == 1:
            return {
                'vertices': [0],
                'simplices': [],
                'neighbors': [],
                'point_indices': [0]
            }

        # Check if all points are the same
        if np.allclose(self.points, self.points[0]):
            return {
                'vertices': [0],
                'simplices': [],
                'neighbors': [],
                'point_indices': [0]
            }

        # Check if points lie on a lower-dimensional space
        rank = np.linalg.matrix_rank(self.points - self.points[0])
        if rank < 4:
            # Project points to their affine hull and compute lower-dim convex hull
            centered = self.points - self.points[0]
            _, _, vh = np.linalg.svd(centered)
            basis = vh[:rank]
            projected = np.dot(centered, basis.T)

            try:
                hull = ConvexHull(projected)
                return {
                    'vertices': hull.vertices.tolist(),
                    'simplices': hull.simplices.tolist(),
                    'neighbors': hull.neighbors.tolist(),
                    'point_indices': hull.points.tolist()
                }
            except:
                # If still degenerate, return all points as vertices
                return {
                    'vertices': list(range(len(self.points))),
                    'simplices': [],
                    'neighbors': [],
                    'point_indices': self.points.tolist()
                }

        # Fallback - shouldn't reach here for valid inputs
        return {
            'vertices': list(range(len(self.points))),
            'simplices': [],
            'neighbors': [],
            'point_indices': self.points.tolist()
        }

def convex_hull_4d(points):
    solver = ConvexHull4D(points)
    return solver.compute()
